import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import { useLanguage } from '../context/LanguageContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

/**
 * ChatBot – Floating chatbot widget for AgriPulse.
 *
 * Features:
 *  - Bottom-right floating icon that opens a popup chat window
 *  - Multilingual UI text via the shared LanguageContext
 *  - Sends user messages + language code to POST /chatbot
 *  - Can receive soil analysis results to explain via soil_context
 *  - Gemini responses appear in the selected language
 *  - Auto-scrolls to latest message
 *
 * Props:
 *  - latestResults: optional array of soil analysis results from the main app
 */
function ChatBot({ latestResults }) {
  const { t, lang } = useLanguage();
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // ── Show welcome message when chat opens ────────────────────
  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setMessages([{ role: 'bot', text: t('chat_welcome') }]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  // ── Update welcome message when language changes ────────────
  useEffect(() => {
    if (messages.length === 1 && messages[0].role === 'bot') {
      setMessages([{ role: 'bot', text: t('chat_welcome') }]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [lang]);

  // ── Auto-scroll to bottom on new messages ───────────────────
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  // ── Focus input when chat opens ─────────────────────────────
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [isOpen]);

  /**
   * Send a message to the backend chatbot endpoint.
   */
  const sendMessage = async (text) => {
    if (!text.trim()) return;

    const userMsg = { role: 'user', text: text.trim() };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      // Build optional soil context from latest results
      let soilContext = null;
      if (latestResults && latestResults.length > 0) {
        soilContext = latestResults[0]; // use first sample as context
      }

      const res = await axios.post(`${API_URL}/chatbot`, {
        language: lang,
        message: text.trim(),
        soil_context: soilContext,
      });

      setMessages((prev) => [
        ...prev,
        { role: 'bot', text: res.data.response },
      ]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { role: 'bot', text: t('chat_error'), isError: true },
      ]);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Handle "Explain my soil results" quick action.
   */
  const explainResults = () => {
    if (latestResults && latestResults.length > 0) {
      sendMessage(t('chat_explain'));
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage(input);
    }
  };

  return (
    <>
      {/* ── Floating Chat Icon ──────────────────────────────── */}
      {!isOpen && (
        <button
          className="chatbot-fab"
          onClick={() => setIsOpen(true)}
          title={t('chat_open')}
          aria-label={t('chat_open')}
        >
          <span className="chatbot-fab-icon">💬</span>
        </button>
      )}

      {/* ── Chat Window ─────────────────────────────────────── */}
      {isOpen && (
        <div className="chatbot-window">
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-header-left">
              <span className="chatbot-header-icon">🌱</span>
              <span className="chatbot-header-title">{t('chat_title')}</span>
            </div>
            <button
              className="chatbot-close"
              onClick={() => setIsOpen(false)}
              aria-label="Close chat"
            >
              ✕
            </button>
          </div>

          {/* Messages Area */}
          <div className="chatbot-messages">
            {messages.map((msg, idx) => (
              <div
                key={idx}
                className={`chatbot-msg ${msg.role === 'user' ? 'chatbot-msg-user' : 'chatbot-msg-bot'} ${msg.isError ? 'chatbot-msg-error' : ''}`}
              >
                {msg.role === 'bot' && (
                  <span className="chatbot-avatar">🤖</span>
                )}
                <div className="chatbot-bubble">{msg.text}</div>
                {msg.role === 'user' && (
                  <span className="chatbot-avatar">👤</span>
                )}
              </div>
            ))}

            {/* Typing indicator */}
            {loading && (
              <div className="chatbot-msg chatbot-msg-bot">
                <span className="chatbot-avatar">🤖</span>
                <div className="chatbot-bubble chatbot-typing">
                  <span className="dot"></span>
                  <span className="dot"></span>
                  <span className="dot"></span>
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Quick Actions */}
          {latestResults && latestResults.length > 0 && (
            <div className="chatbot-quick-actions">
              <button
                className="chatbot-quick-btn"
                onClick={explainResults}
                disabled={loading}
              >
                📊 {t('chat_explain')}
              </button>
            </div>
          )}

          {/* Input Area */}
          <div className="chatbot-input-area">
            <input
              ref={inputRef}
              type="text"
              className="chatbot-input"
              placeholder={t('chat_placeholder')}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              disabled={loading}
            />
            <button
              className="chatbot-send"
              onClick={() => sendMessage(input)}
              disabled={loading || !input.trim()}
              aria-label={t('chat_send')}
            >
              {t('chat_send')}
            </button>
          </div>
        </div>
      )}
    </>
  );
}

export default ChatBot;
